import React, { useState, useEffect } from "react";
import {
  UsersIcon,
  AcademicCapIcon,
  ChartBarIcon,
  ArrowDownTrayIcon,
} from "@heroicons/react/24/outline";
import {
  AreaChart,
  Area,
  XAxis,
  YAxis,
  CartesianGrid,
  Tooltip,
  ResponsiveContainer,
  BarChart,
  Bar,
  Legend,
  PieChart,
  Pie,
  Cell,
} from "recharts";

// --- MOCK DATA (Replace with your API calls later) ---
const userGrowthData = [
  { month: "Jan", users: 400 },
  { month: "Feb", users: 600 },
  { month: "Mar", users: 800 },
  { month: "Apr", users: 1200 },
  { month: "May", users: 1500 },
  { month: "Jun", users: 2100 },
];

const quizStatsData = [
  { subject: "Math", attempts: 120, avgScore: 85 },
  { subject: "Science", attempts: 98, avgScore: 78 },
  { subject: "History", attempts: 86, avgScore: 92 },
  { subject: "English", attempts: 150, avgScore: 88 },
];

const roleDistribution = [
  { name: "Students", value: 1800 },
  { name: "Academic Panel", value: 45 },
  { name: "Admins", value: 5 },
];

const PIE_COLORS = ["#10b981", "#6366f1", "#ef4444"]; // Green, Indigo, Red

export default function AdminReports() {
  const [loading, setLoading] = useState(true);

  // Simulate data fetching
  useEffect(() => {
    const timer = setTimeout(() => {
      setLoading(false);
    }, 800);
    return () => clearTimeout(timer);
  }, []);

  const handleExport = () => {
    alert("Exporting report as PDF/CSV... (Implement your export logic here)");
  };

  if (loading) {
    return (
      <div className="min-h-screen w-[83vw] ml-[17vw] bg-gradient-to-br from-slate-900 via-gray-900 to-slate-800 flex items-center justify-center text-white">
        <p className="text-xl animate-pulse">Loading Reports...</p>
      </div>
    );
  }

  return (
    <div className="min-h-screen w-[83vw] ml-[17vw] bg-gradient-to-br from-slate-900 via-gray-900 to-slate-800 p-8 text-white">

      {/* HEADER */}
      <div className="flex justify-between items-center mb-8 mt-10">
        <div>
          <h1 className="text-3xl font-bold">Platform Analytics</h1>
          <p className="text-gray-400 mt-1">Real-time overview of Smart Learning metrics</p>
        </div>

        <button
          onClick={handleExport}
          className="flex items-center gap-2 px-4 py-2 bg-indigo-600 hover:bg-indigo-700 rounded-lg font-medium shadow-lg shadow-indigo-500/30 transition"
        >
          <ArrowDownTrayIcon className="w-5 h-5" />
          Export Report
        </button>
      </div>

      {/* SUMMARY CARDS */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-6 mb-8">
        <StatCard
          title="Total Users"
          value="2,100"
          trend="+12% this month"
          icon={<UsersIcon className="w-8 h-8 text-blue-400" />}
          color="border-blue-500/30"
        />
        <StatCard
          title="Quizzes Attempted"
          value="14,320"
          trend="+8% this week"
          icon={<AcademicCapIcon className="w-8 h-8 text-green-400" />}
          color="border-green-500/30"
        />
        <StatCard
          title="Average Score"
          value="84.5%"
          trend="+2.1% overall"
          icon={<ChartBarIcon className="w-8 h-8 text-purple-400" />}
          color="border-purple-500/30"
        />
      </div>

      {/* CHARTS SECTION */}
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 mb-8">

        {/* CHART 1: User Growth (Area Chart) */}
        <div className="bg-white/5 backdrop-blur-lg border border-white/10 p-6 rounded-2xl shadow-xl">
          <h3 className="text-lg font-semibold mb-4 text-indigo-300">User Growth (Last 6 Months)</h3>
          <div className="h-72">
            <ResponsiveContainer width="100%" height="100%">
              <AreaChart data={userGrowthData}>
                <defs>
                  <linearGradient id="colorUsers" x1="0" y1="0" x2="0" y2="1">
                    <stop offset="5%" stopColor="#6366f1" stopOpacity={0.8} />
                    <stop offset="95%" stopColor="#6366f1" stopOpacity={0} />
                  </linearGradient>
                </defs>
                <CartesianGrid strokeDasharray="3 3" stroke="#ffffff1a" />
                <XAxis dataKey="month" stroke="#9ca3af" />
                <YAxis stroke="#9ca3af" />
                <Tooltip
                  contentStyle={{ backgroundColor: "#1e293b", border: "none", borderRadius: "8px" }}
                  itemStyle={{ color: "#fff" }}
                />
                <Area type="monotone" dataKey="users" stroke="#818cf8" fillOpacity={1} fill="url(#colorUsers)" />
              </AreaChart>
            </ResponsiveContainer>
          </div>
        </div>

        {/* CHART 2: Subject Performance (Bar Chart) */}
        <div className="bg-white/5 backdrop-blur-lg border border-white/10 p-6 rounded-2xl shadow-xl">
          <h3 className="text-lg font-semibold mb-4 text-indigo-300">Quiz Engagement by Subject</h3>
          <div className="h-72">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={quizStatsData}>
                <CartesianGrid strokeDasharray="3 3" stroke="#ffffff1a" />
                <XAxis dataKey="subject" stroke="#9ca3af" />
                <YAxis yAxisId="left" orientation="left" stroke="#9ca3af" />
                <Tooltip
                  contentStyle={{ backgroundColor: "#1e293b", border: "none", borderRadius: "8px" }}
                />
                <Legend wrapperStyle={{ paddingTop: "20px" }} />
                <Bar yAxisId="left" dataKey="attempts" name="Attempts" fill="#34d399" radius={[4, 4, 0, 0]} />
              </BarChart>
            </ResponsiveContainer>
          </div>
        </div>

        {/* CHART 3: User Roles (Pie Chart) */}
        <div className="bg-white/5 backdrop-blur-lg border border-white/10 p-6 rounded-2xl shadow-xl lg:col-span-2">
          <h3 className="text-lg font-semibold mb-4 text-indigo-300 text-center">User Role Distribution</h3>
          <div className="h-64 flex justify-center">
            <ResponsiveContainer width="100%" height="100%">
              <PieChart>
                <Pie
                  data={roleDistribution}
                  cx="50%"
                  cy="50%"
                  innerRadius={60}
                  outerRadius={100}
                  paddingAngle={5}
                  dataKey="value"
                  label={({ name, percent }) => `${name} ${(percent * 100).toFixed(0)}%`}
                >
                  {roleDistribution.map((entry, index) => (
                    <Cell key={`cell-${index}`} fill={PIE_COLORS[index % PIE_COLORS.length]} />
                  ))}
                </Pie>
                <Tooltip contentStyle={{ backgroundColor: "#1e293b", border: "none", borderRadius: "8px" }} />
              </PieChart>
            </ResponsiveContainer>
          </div>
        </div>

      </div>
    </div>
  );
}

